const response = $input.first().json.response;
let data;

try {
  const clean = response.replace(/```json/g, '').replace(/```/g, '').trim();
  data = JSON.parse(clean);
} catch (e) {
  return { json: { error: 'Failed to parse AI response' } };
}

const studentName = $node['Build Prompt'].json.studentName;
const studentId = $node['Build Prompt'].json.studentId;
const firstName = studentName.split(' ')[0];

const feedbackText = `Dear ${firstName},

This is AI-generated formative feedback to help you improve your work.
Use it to guide revision before submitting to your instructor.

═══════════════════════════════════════════════════════
FORMATIVE FEEDBACK REPORT
═══════════════════════════════════════════════════════

Student: ${studentName}
ID: ${studentId}
Generated: ${new Date().toLocaleString()}

─── PART 1: CUSTOMER EXPERIENCE ANALYSIS ───
${data.feedback.part1}

─── PART 2: SERVICE RECOVERY ───
${data.feedback.part2}

─── PART 3: STRATEGY PROPOSAL ───
${data.feedback.part3}

─── YOUR STRENGTHS ───
${data.strengths.map((s, i) => `${i+1}. ${s}`).join('\n')}

─── AREAS TO DEVELOP ───
${data.improvements.map((s, i) => `${i+1}. ${s}`).join('\n')}

─── RECOMMENDED NEXT STEPS ───
${data.next_steps.map((s, i) => `${i+1}. ${s}`).join('\n')}

═══════════════════════════════════════════════════════
IMPORTANT REMINDERS:
- This is formative feedback to support your learning
- You can request feedback multiple times as you revise
- Final grades are determined by your instructor
- Use this to improve, not as a grade prediction
═══════════════════════════════════════════════════════
`;

return {
  json: { feedbackText, studentName, studentId },
  binary: {
    data: {
      data: Buffer.from(feedbackText, 'utf-8').toString('base64'),
      mimeType: 'text/plain',
      fileName: `Feedback_${studentName.replace(/\s/g, '_')}_${studentId}.txt`
    }
  }
};
